  "verses": [
    {
      "n": 22,
      "column": "left",
      "text": "Un wiſs / fo tas Ne-\nschkihſts aiſkarr / tas taps ne-\nschkihſts / un furra Dwehfele to\naiſkahrs / tai buhs neschkihſtai\nbuht lihds Wakkaram.\n"
    },
    {
      "n": 1,
      "column": "left",
      "text": "Ad nahze wiſa Israëta\nBehrnu Draudse / pir-\nmá Mehneſi eekſch tahs\nTukfneses Sin / un tee Laudis\napmettahs Rahdetá / un Mirja-\nme nomirre tur / un tappe tur ap-\nrakta.\n"
    },
    {
      "n": 2,
      "column": "left",
      "text": "Un tur ne bija Uhdens\npreekſch tahs Draudses / tad fa-\npulzejahs tee prett Mohsu / un\nprett Aärönu.\n"
    },
    {
      "n": 3,
      "column": "left",
      "text": "Un tee Laudis bahrahs ar\nMohsu/ un runnaja/ fazzidami:\nKaut mehs buhtum postá gahju-\nfchi / kad muhfu Brabti pohsta\ngahje preekſch to KUNGii.\n"
    },
    {
      "n": 4,
      "column": "left",
      "text": "Kapehz effat juhs ta KUN-\nGA Draudſi us fcho Tukſneti\nwedduſchi za fche jamirst mums/\nun muhſeem Lohpeerin.\n"
    },
    {
      "n": 5,
      "column": "right",
      "text": "Un kapehz effat juhs muh-\nlikkuſchi augſchop eet no Egiptee\nSemmes waddidami muhs u\nſcho faunu Weetu/ ta ne irr fehja\nma Weeta / nedß Wiḥgu-ned\nWiḥnu-Dahrsu/nedß Granatu\nAhbotu Weeta/ tur arri Uyden\nnewa/ ka dsert warr.\n"
    },
    {
      "n": 6,
      "column": "right",
      "text": "Tad gahje Mohsus un Aä\nrons no tahs Draudses / preekſc\ntahs Sa-eefchanas Telts Dur\nwin / un mettahs us faueeen\nWaigeem/un ta KUNGA Goh\ndiva rahdijahs winneem.\n"
    },
    {
      "n": 7,
      "column": "right",
      "text": "Tad runnaja tas KUNG-\nus Mohsu/ un fazzija:\n"
    },
    {
      "n": 8,
      "column": "right",
      "text": "Neimm to Sisli/ un faput\nzini to Draudſi / tu un Aäröns\ntaws Brahlis/ un runnajeet ust\nAkmixa-Kalnu preekſch winnu\nAzzim/ tad dohs winſch fawu Uh-\ndeni/tá isdabbuſchet juhs winxeem\nUhdeni no ta Akmixa-Kalna / un\ndsirdinaſeet to Draudſt un win-\nnas Lohpus.\n"
    },
    {
      "n": 9,
      "column": "right",
      "text": "Tad nehme Mohsus to Sis-\nli no ta KUNGA Preekſchas/it-\ntin ka winſch tam bij pawehlejis.\n"
    },
    {
      "n": 10,
      "column": "right",
      "text": "Un Mohsus un Aäröns fa-\npulzeja to Draudſt preekſch to Ak-\nwina-Kalna/ un winſch fazzija us\nteem: Klansajt jelle juhs Pahr-\ngalwigee/ arrig mehs isdabbuſim\njums Uhdeni no fcha Akmixa-\nKalna?\n"
    },
    {
      "n": 11,
      "column": "right",
      "text": "Tad pazehle Mohsus fa-\nwu Rohfu un fitte to Akmixa-\nKalnu ar fawu Sisli divireisi/tad\nnahze dauds Uhdens aha/ta ka ta\nDraudſe un winnas Lohpi dſehre.\n"
    }
  ],
